using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// "Banco de dados" de variáveis globais configuráveis no Inspector (Etapa 8):
/// bools/ints/floats/strings nomeados, criados/editados/removidos no editor de
/// GameVariables, lidos e escritos por Action_Set*Variable / Condition_*Variable
/// com "scope = Global". Permite montar lógica de eventos "trigger" sem código
/// (ex: ligar "porta_aberta" = true num evento, condicionar outro a essa variável
/// estar true).
///
/// Para variáveis próprias de um único NPC, usa "scope = Local" — ver
/// NpcController.localVariables.
/// </summary>
public class GameVariables : MonoBehaviour
{
    public static GameVariables Instance { get; private set; }

    [Tooltip("Variáveis globais, partilhadas por todos os eventos do jogo. Usa \"+ Adicionar Variável\" — nomes duplicados são assinalados.")]
    [SerializeField] private List<GameVariable> globalVariables = new List<GameVariable>();

    /// <summary>
    /// Marca instâncias criadas automaticamente por <see cref="EnsureExists"/>
    /// antes da primeira cena carregar (ver PlayerProgress.cs para a explicação
    /// completa — Tarefa #15 "GameBootstrap e singletons"). Sem isto, uma
    /// GameVariables configurada numa cena (com "globalVariables" preenchida no
    /// Inspector) seria destruída ao encontrar a versão vazia auto-criada como
    /// Instance, perdendo todas as variáveis configuradas.
    /// </summary>
    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        // Tarefa #22 (Menu Inicial — "Novo Jogo"): ver PlayerProgress.cs para a
        // explicação completa do mecanismo de fotografia/restauro.
        _initialSnapshotJson = JsonUtility.ToJson(this);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(GameVariables) + " (Fallback)");
        var instance = go.AddComponent<GameVariables>();
        instance.isAutoFallback = true;
    }

    // ---------------- Novo Jogo (Tarefa #22) ----------------

    private string _initialSnapshotJson;

    /// <summary>Repõe todas as variáveis globais para os valores configurados no Inspector no arranque — ver PlayerProgress.ResetForNewGame.</summary>
    public void ResetForNewGame()
    {
        if (!string.IsNullOrEmpty(_initialSnapshotJson))
            JsonUtility.FromJsonOverwrite(_initialSnapshotJson, this);
    }

    public bool GetBool(string name, bool defaultValue = false) => GameVariableListUtil.GetBool(globalVariables, name, defaultValue);
    public int GetInt(string name, int defaultValue = 0) => GameVariableListUtil.GetInt(globalVariables, name, defaultValue);
    public float GetFloat(string name, float defaultValue = 0f) => GameVariableListUtil.GetFloat(globalVariables, name, defaultValue);
    public string GetString(string name, string defaultValue = "") => GameVariableListUtil.GetString(globalVariables, name, defaultValue);

    public void SetBool(string name, bool value) => GameVariableListUtil.SetBool(globalVariables, name, value);
    public void SetInt(string name, int value) => GameVariableListUtil.SetInt(globalVariables, name, value);
    public void SetFloat(string name, float value) => GameVariableListUtil.SetFloat(globalVariables, name, value);
    public void SetString(string name, string value) => GameVariableListUtil.SetString(globalVariables, name, value);

    // ---------------- Save / Load ----------------

    /// <summary>Copia todas as variáveis globais para "data" (usado por SaveManager ao gravar).</summary>
    public void CaptureTo(SaveData data)
    {
        data.globalVariables = new List<GameVariable>();
        foreach (var v in globalVariables)
        {
            data.globalVariables.Add(new GameVariable
            {
                variableName = v.variableName,
                type = v.type,
                boolValue = v.boolValue,
                intValue = v.intValue,
                floatValue = v.floatValue,
                stringValue = v.stringValue
            });
        }
    }

    /// <summary>Substitui as variáveis globais pelas guardadas em "data" (usado por SaveManager ao carregar).</summary>
    public void RestoreFrom(SaveData data)
    {
        if (data == null) return;

        globalVariables.Clear();
        if (data.globalVariables == null) return;

        foreach (var v in data.globalVariables)
        {
            globalVariables.Add(new GameVariable
            {
                variableName = v.variableName,
                type = v.type,
                boolValue = v.boolValue,
                intValue = v.intValue,
                floatValue = v.floatValue,
                stringValue = v.stringValue
            });
        }
    }
}
